sql:
SELECT player_name
FROM players
WHERE draft_year = 2012;

SELECT p.player_name, c.coach_name
FROM players p
LEFT JOIN coaches c ON p.team_id = c.team_id;

SELECT DISTINCT c.coach_name
FROM coaches c
INNER JOIN seasons s ON c.team_id = s.champion_team_id;

SELECT c.coach_name
FROM coaches c
INNER JOIN users u ON c.coach_name = u.first_name || ' ' || u.last_name;

